class Solution {
public:
    int numberOfSpecialChars(string word) {
        int lower[26] = {0};
        int upper[26] = {0};
        bool seenUpper[26] = {false};

        for (char c : word) {
            if (islower(c)) {
                lower[c - 'a']++;
            } else {
                seenUpper[c - 'A'] = true;
            }
        }

        int count = 0;
        for (int i = 0; i < 26; ++i) {
